import React, { useState, useEffect } from 'react';
import '../styles/Katalog.css';

const Keranjang = ({ keranjang, setKeranjang }) => {
  const [barangDipilih, setBarangDipilih] = useState([]);

  useEffect(() => {
    setBarangDipilih(keranjang.map(item => item.id));
  }, [keranjang.length]);

  const aturPilihSemua = (e) => {
    if (e.target.checked) {
      setBarangDipilih(keranjang.map(item => item.id));
    } else {
      setBarangDipilih([]);
    }
  };

  const aturPilihBarang = (id) => {
    if (barangDipilih.includes(id)) {
      setBarangDipilih(barangDipilih.filter(itemId => itemId !== id));
    } else {
      setBarangDipilih([...barangDipilih, id]);
    }
  };

  const ubahJumlah = (id, angka) => {
    setKeranjang(keranjang.map(item => {
      if (item.id === id) {
        const jumlahBaru = item.jumlah + angka;
        return { ...item, jumlah: jumlahBaru > 0 ? jumlahBaru : 1 };
      }
      return item;
    }));
  };

  const ubahCatatan = (id, teks) => {
    setKeranjang(keranjang.map(item => 
      item.id === id ? { ...item, catatan: teks } : item
    ));
  };

  const hapusBarangTerpilih = () => {
    setKeranjang(keranjang.filter(item => !barangDipilih.includes(item.id)));
    setBarangDipilih([]);
  };

  const itemTerpilih = keranjang.filter(item => barangDipilih.includes(item.id));
  const totalJumlahBarang = itemTerpilih.reduce((total, item) => total + item.jumlah, 0);
  const totalHargaBelanja = itemTerpilih.reduce((total, item) => {
    const hargaAngka = parseInt(item.harga.replace(/[^0-9]/g, ''));
    return total + (hargaAngka * item.jumlah);
  }, 0);

  return (
    <div className="katalog-wrapper">
      <div className="katalog-overlay"></div>
      
      <div className="katalog-content" style={{ display: 'flex', gap: '30px', alignItems: 'flex-start' }}>
        
        <div style={{ flex: '2', background: 'white', borderRadius: '8px', border: '2px solid #38bdf8', overflow: 'hidden' }}>
          <div style={{ padding: '15px 20px', borderBottom: '1px solid #eee', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <input 
                type="checkbox" 
                checked={barangDipilih.length === keranjang.length && keranjang.length > 0}
                onChange={aturPilihSemua}
                style={{ width: '18px', height: '18px', cursor: 'pointer' }}
              />
              <span style={{ fontSize: '14px', color: '#555' }}>Pilih Semua</span>
            </div>
            <span 
              onClick={hapusBarangTerpilih} 
              style={{ color: '#ef4444', fontSize: '14px', fontWeight: 'bold', cursor: 'pointer' }}
            >
              Hapus
            </span>
          </div>

          <div style={{ padding: '0 20px' }}>
            {keranjang.map(item => (
              <div key={item.id} style={{ display: 'flex', alignItems: 'center', padding: '20px 0', borderBottom: '1px solid #eee', gap: '15px' }}>
                <input 
                  type="checkbox" 
                  checked={barangDipilih.includes(item.id)}
                  onChange={() => aturPilihBarang(item.id)}
                  style={{ width: '18px', height: '18px', cursor: 'pointer' }}
                />
                <img src={item.img} alt={item.nama} style={{ width: '90px', height: '90px', borderRadius: '8px', objectFit: 'cover' }} />
                
                <div style={{ flex: '1' }}>
                  <h4 style={{ margin: '0 0 5px 0', fontSize: '16px', color: '#111' }}>{item.nama}</h4>
                  <p style={{ margin: '0 0 10px 0', fontSize: '14px', color: '#666' }}>{item.harga}</p>
                  <input 
                    type="text" 
                    placeholder="Catatan" 
                    value={item.catatan || ''}
                    onChange={(e) => ubahCatatan(item.id, e.target.value)}
                    style={{ width: '100%', padding: '8px 12px', background: '#e5e7eb', border: 'none', borderRadius: '4px', fontSize: '12px', color: '#4b5563', outline: 'none' }}
                  />
                </div>

                <div style={{ display: 'flex', alignItems: 'center', border: '1px solid #ddd', borderRadius: '6px', overflow: 'hidden', height: '32px' }}>
                  <button onClick={() => ubahJumlah(item.id, -1)} style={{ width: '32px', background: 'white', border: 'none', borderRight: '1px solid #ddd', cursor: 'pointer', fontSize: '16px', color: '#555' }}>-</button>
                  <span style={{ width: '40px', textAlign: 'center', fontSize: '14px', fontWeight: 'bold', color: '#111' }}>{item.jumlah}</span>
                  <button onClick={() => ubahJumlah(item.id, 1)} style={{ width: '32px', background: 'white', border: 'none', borderLeft: '1px solid #ddd', cursor: 'pointer', fontSize: '16px', color: '#555' }}>+</button>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div style={{ flex: '1', background: 'white', borderRadius: '8px', padding: '25px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
          <h3 style={{ margin: '0 0 20px 0', fontSize: '16px', color: '#111' }}>Ringkasan Belanja</h3>
          
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '15px', color: '#666', fontSize: '14px' }}>
            <span>Total Harga ({totalJumlahBarang} Barang)</span>
            <span>Rp {totalHargaBelanja.toLocaleString('id-ID')}</span>
          </div>
          
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '25px', color: '#111', fontSize: '16px', fontWeight: 'bold' }}>
            <span>Total Belanja</span>
            <span>Rp {totalHargaBelanja.toLocaleString('id-ID')}</span>
          </div>

          <button style={{ width: '100%', padding: '14px', background: '#b45309', color: 'white', border: 'none', borderRadius: '6px', fontSize: '14px', fontWeight: 'bold', cursor: 'pointer', transition: 'background 0.3s' }}>
            Login untuk Checkout
          </button>
        </div>

      </div>
    </div>
  );
};

export default Keranjang;
